import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def build_lookup(data):
    lookup = {}
    for proj in data['projects']:
        pname = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw['topLevelPackages']:
                lookup[(pname, fw['framework'], pkg['id'])] = pkg['resolvedVersion']
    return lookup

bl = build_lookup(baseline)
al = build_lookup(after)

all_keys = sorted(set(bl.keys()) | set(al.keys()))

changes = []
unchanged = []
for k in all_keys:
    bv = bl.get(k, 'N/A')
    av = al.get(k, 'N/A')
    if bv != av:
        changes.append((k[0], k[1], k[2], bv, av))
    else:
        unchanged.append((k[0], k[1], k[2], bv))

print('=== CHANGES ===')
if changes:
    for c in changes:
        print(f'  {c[0]} ({c[1]}) | {c[2]} | {c[3]} -> {c[4]}')
else:
    print('  None')

print()
print(f'=== UNCHANGED: {len(unchanged)} packages ===')
for u in unchanged:
    print(f'  {u[0]} ({u[1]}) | {u[2]} | {u[3]}')
"

